  it('empty item list → premium 5 G (processing fee only)', () => {
    expect(runQuote([])).toBe(5);
  });

  it('quote includes unknown item type → error', () => {
    const scenario: Scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: 'quote', items: [{ type: 'broomstick' } as any] },
      ],
