// Core domain types and logic for the MHPCO claim office.

export type ItemType = 'sword' | 'amulet' | 'staff' | 'potion' | 'rune' | 'moonstone';

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Customer {
  yearsWithMHPCO: number;
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export type Step =
  | { op: 'quote'; items: Item[] }
  | { op: 'claim'; policy: number; incident: Incident };

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export type StepResult =
  | { premium: number }
  | { payout: number; remainingCap: number };

export interface ScenarioResult {
  results: StepResult[];
}

interface Policy {
  items: Item[];
  insuranceSum: number;
  remainingCap: number;
}

interface PriceListEntry {
  insuranceValue: number;
  basePremium: number;
}

const MAIN_ITEM_PRICES: Record<string, PriceListEntry> = {
  sword:  { insuranceValue: 1000, basePremium: 100 },
  amulet: { insuranceValue: 600,  basePremium: 60 },
  staff:  { insuranceValue: 800,  basePremium: 80 },
  potion: { insuranceValue: 400,  basePremium: 40 },
};

const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
const COMPONENT_INSURANCE_VALUE = 250;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_BASE_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const PROCESSING_FEE = 5;
const DEDUCTIBLE = 100;

function isKnownType(type: string): boolean {
  return type in MAIN_ITEM_PRICES || COMPONENT_TYPES.has(type);
}

function isComponent(type: string): boolean {
  return COMPONENT_TYPES.has(type);
}

function itemInsuranceValue(item: Item): number {
  if (item.type in MAIN_ITEM_PRICES) {
    return MAIN_ITEM_PRICES[item.type].insuranceValue;
  }
  if (isComponent(item.type)) {
    return COMPONENT_INSURANCE_VALUE;
  }
  throw new Error(`Unknown item type: ${item.type}`);
}

function policyInsuranceSum(items: Item[]): number {
  return items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
}

function itemBasePremium(item: Item): number {
  if (item.type in MAIN_ITEM_PRICES) {
    return MAIN_ITEM_PRICES[item.type].basePremium;
  }
  if (isComponent(item.type)) {
    return COMPONENT_BASE_PREMIUM;
  }
  throw new Error(`Unknown item type: ${item.type}`);
}

// Compute total base premium for items, applying the block discount for
// components: each group of exactly 3 alike components is one block at 60 G;
// remaining components are billed at 25 G each.
function itemsBasePremium(items: Item[]): number {
  const componentCounts: Record<string, number> = {};
  let total = 0;

  for (const item of items) {
    if (isComponent(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += itemBasePremium(item);
    }
  }

  for (const type in componentCounts) {
    const count = componentCounts[type];
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const remainder = count % COMPONENT_BLOCK_SIZE;
    total += blocks * COMPONENT_BLOCK_BASE_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
  }

  return total;
}

function itemSurcharge(item: Item): number {
  const base = itemBasePremium(item);
  let surcharge = 0;
  if (item.cursed) {
    surcharge += base * 0.5;
  }
  if ((item.enchantment ?? 0) >= 5) {
    surcharge += base * 0.3;
  }
  return surcharge;
}

function itemsSurcharge(items: Item[]): number {
  return items.reduce((sum, item) => sum + itemSurcharge(item), 0);
}

function roundUp(value: number): number {
  return Math.ceil(value);
}

function roundDown(value: number): number {
  return Math.floor(value);
}

export function computePremium(
  customer: Customer,
  items: Item[],
  isFollowUp: boolean,
): number {
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  const policyBase = itemsBasePremium(items);
  const itemSurcharges = itemsSurcharge(items);

  // Item base + item-specific surcharges form the per-item subtotal.
  // Policy-wide modifiers apply to policyBase (per the spec: loyalty,
  // first-insurance and follow-up are described as policy-wide; the
  // first-insurance modifier is treated per-item per the integration note).
  let total = policyBase + itemSurcharges;

  // First insurance surcharge: 10% per item, applied to that item's base.
  for (const item of items) {
    total += itemBasePremium(item) * 0.1;
  }

  if (customer.yearsWithMHPCO >= 2) {
    total -= policyBase * 0.2;
  }
  if (isFollowUp) {
    total -= policyBase * 0.15;
  }

  total += PROCESSING_FEE;
  return roundUp(total);
}

function makePolicy(items: Item[]): Policy {
  const insuranceSum = policyInsuranceSum(items);
  return {
    items: [...items],
    insuranceSum,
    remainingCap: insuranceSum * 2,
  };
}

function damageReimbursement(item: Item, amount: number): number {
  const highEnchant = (item.enchantment ?? 0) >= 8;
  if (highEnchant) {
    return amount * 0.5;
  }
  return amount;
}

export function computeClaim(
  policy: Policy,
  incident: Incident,
): { payout: number; remainingCap: number } {
  if (incident.damages.some((d) => d.amount < 0)) {
    throw new Error('Negative damage amount');
  }

  // Validate: every damage must correspond to an actual covered item.
  // Map item types to a queue of items so multiple of same type are matched.
  const available: Record<string, Item[]> = {};
  for (const item of policy.items) {
    if (!available[item.type]) available[item.type] = [];
    available[item.type].push(item);
  }
  const matched: { item: Item; amount: number }[] = [];
  const consumed: Record<string, number> = {};
  for (const dmg of incident.damages) {
    if (!isKnownType(dmg.itemType)) {
      throw new Error(`Unknown item type in damage: ${dmg.itemType}`);
    }
    const pool = available[dmg.itemType] ?? [];
    const used = consumed[dmg.itemType] ?? 0;
    if (used >= pool.length) {
      throw new Error(`Damage references item not in policy: ${dmg.itemType}`);
    }
    matched.push({ item: pool[used], amount: dmg.amount });
    consumed[dmg.itemType] = used + 1;
  }

  let totalPayout = 0;
  for (const { item, amount } of matched) {
    const reimbursed = damageReimbursement(item, amount);
    const afterDeductible = Math.max(0, reimbursed - DEDUCTIBLE);
    totalPayout += afterDeductible;
  }

  let payout = roundDown(totalPayout);
  if (payout > policy.remainingCap) {
    payout = policy.remainingCap;
  }
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
}

export function runScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = [];
  const policies: (Policy | null)[] = [];
  let quoteCount = 0;

  for (const step of scenario.steps) {
    if (step.op === 'quote') {
      const isFollowUp = quoteCount > 0;
      const premium = computePremium(scenario.customer, step.items, isFollowUp);
      const policy = makePolicy(step.items);
      policies.push(policy);
      results.push({ premium });
      quoteCount += 1;
    } else if (step.op === 'claim') {
      const policy = policies[step.policy];
      if (!policy) {
        throw new Error(`Claim references nonexistent policy: ${step.policy}`);
      }
      const result = computeClaim(policy, step.incident);
      policies.push(null);
      results.push(result);
    } else {
      throw new Error(`Unknown op`);
    }
  }

  return { results };
}

