94	// Compute total base premium for items, applying the block discount for
95	// components: each group of exactly 3 alike components is one block at 60 G;
96	// remaining components are billed at 25 G each.
97	function itemsBasePremium(items: Item[]): number {
98	  const componentCounts: Record<string, number> = {};
99	  let total = 0;
100	
101	  for (const item of items) {
102	    if (isComponent(item.type)) {
103	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
104	    } else {
